import React from 'react';
import {Pressable, Text, View} from 'react-native';
import Animated, {useAnimatedStyle, useReducedMotion, useSharedValue, withSpring, withTiming} from 'react-native-reanimated';
export function PageTransitionStackRevealWithParallaxInteraction({onActivate}) {
  const reduceMotion = useReducedMotion();
  const progress = useSharedValue(0);
  const style = useAnimatedStyle(() => ({transform: [{scale: 1 + progress.value * 0.04}], opacity: 0.92 + progress.value * 0.08}));
  const activate = () => { progress.value = reduceMotion ? 1 : withSpring(1, {damping:18, stiffness:220}); onActivate?.(); };
  return <View><Animated.View style={style}><Pressable accessibilityRole="button" accessibilityLabel="Page transition: stack reveal with parallax" accessibilityHint="Activates without requiring motion or gestures" accessibilityActions={[{name:'activate',label:'Activate'}]} onAccessibilityAction={activate} hitSlop={{top:8,right:8,bottom:8,left:8}} style={{minHeight:44,minWidth:44}} onPressIn={() => { progress.value = withTiming(1, {duration: reduceMotion ? 0 : 120}); }} onPressOut={() => { progress.value = withTiming(0, {duration: reduceMotion ? 0 : 160}); }} onPress={activate}><Text>Page transition: stack reveal with parallax</Text></Pressable></Animated.View></View>;
}

