import React from 'react';
import {StyleSheet, View} from 'react-native';
import {Canvas, Path, Skia, Group} from '@shopify/react-native-skia';
import {useSharedValue, useFrameCallback, useDerivedValue} from 'react-native-reanimated';
export function WaveFill({progress, width, height, color = '#0A84FF'}: {progress: number; width: number; height: number; color?: string}) {
  const phase = useSharedValue(0);
  useFrameCallback(({timeSinceFirstFrame}) => { phase.value = (timeSinceFirstFrame / 1000) * 60; });
  const wavePath = useDerivedValue(() => { const p = Skia.Path.Make(); const baseY = height * (1 - progress); p.moveTo(0, height); p.lineTo(0, baseY); for (let x = 0; x <= width; x += 4) { const y = baseY + Math.sin((x + phase.value) / 60 * Math.PI * 2) * 6; p.lineTo(x, y); } p.lineTo(width, height); p.close(); return p; });
  return (<View style={{width, height, borderRadius: 16, overflow:'hidden', backgroundColor:'#1C1C1E'}}><Canvas style={StyleSheet.absoluteFill}><Path path={wavePath} color={color}/></Canvas></View>);
}

